#include "../common.h"
#include "../util/timer/timer.h"
#include "./kernel_gpu_cuda_wrapper_2.h"

#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

void 
findRangeK_openmp(	long height,
					knode *knodes,
					long knodes_elem,
					long *currKnode,
					long *offset,
					long *lastKnode,
					long *offset_2,
					int *start,
					int *end,
					int *Recstart,
					int *Reclen,
					int count,
					int order)
{
	#pragma omp parallel for
	for(int bid = 0; bid < count; bid++) {
		long currKnode_bid = currKnode[bid];
		long lastKnode_bid = lastKnode[bid];
		long offset_bid = offset[bid];
		long offset_2_bid = offset_2[bid];
		int start_bid = start[bid];
		int end_bid = end[bid];

		int i;
		for(i = 0; i < height; i++) {
			int thid;
			for(thid = 0; thid < order; thid++) {
				if((knodes[currKnode_bid].keys[thid] <= start_bid) && 
				   (knodes[currKnode_bid].keys[thid+1] > start_bid)) {
					if(knodes[currKnode_bid].indices[thid] < knodes_elem) {
						offset_bid = knodes[currKnode_bid].indices[thid];
					}
				}
				if((knodes[lastKnode_bid].keys[thid] <= end_bid) && 
				   (knodes[lastKnode_bid].keys[thid+1] > end_bid)) {
					if(knodes[lastKnode_bid].indices[thid] < knodes_elem) {
						offset_2_bid = knodes[lastKnode_bid].indices[thid];
					}
				}
			}

			currKnode_bid = offset_bid;
			lastKnode_bid = offset_2_bid;
		}

		for(int thid = 0; thid < order; thid++) {
			if(knodes[currKnode_bid].keys[thid] == start_bid) {
				Recstart[bid] = knodes[currKnode_bid].indices[thid];
				break;
			}
		}

		for(int thid = 0; thid < order; thid++) {
			if(knodes[lastKnode_bid].keys[thid] == end_bid) {
				Reclen[bid] = knodes[lastKnode_bid].indices[thid] - Recstart[bid] + 1;
				break;
			}
		}
	}
}

